import Foundation

func solve(nums: [Int64], k: Int64) -> Int64 {
    let n = nums.count
    if n == 0 {
        return 0
    }
    var max_size = 1
    nums.sort()
    for i in 0..<n {
        let target = k * nums[i]
        var left = i
        var right = n - 1
        var j = -1
        while left <= right {
            let mid = (left + right) / 2
            if nums[mid] <= target {
                j = mid
                left = mid + 1
            } else {
                right = mid - 1
            }
        }
        if j >= i {
            let current_size = j - i + 1
            if current_size > max_size {
                max_size = current_size
            }
        }
    }
    return Int64(n - max_size)
}
